Patch Set 7:

Andreas, since the lod pool_desc and changed a lot. Minimal linking the same file from lod -> lov would not work out. I am sure a minimal after lod changes. There are very few genuine common code that could be utilized. However, here is what I was trying. This is by no way complete, just an idea. The present patch which is pushed does not make any functional changes. It has just adapted your push to make space/tabs changes. Only significant change is that 'struct pool_desc' under lod and lov layer now has a prefix to correctly mark it.

enum comm_pool_type /* enum for common pool type */
{
	LOV_POOL_TAG = 10,
	LOD_POOL_TAG = 11
};

/* lov pool_desc Now becomes lov_pool_desc 
   lod pool_desc now becomes lod_pool_desc */
+struct lov_pool_desc {
        char                     pool_name[LOV_MAXPOOLNAME + 1];
        struct lu_tgt_pool       pool_obds;
        atomic_t                 pool_refcount;
@@ -237,6 +248,7 @@ struct pool_desc {
        struct rcu_head          pool_rcu;
        struct proc_dir_entry   *pool_proc_entry;
        struct obd_device       *pool_lobd;     /* owner */
+       enum comm_pool_type      pool_tag; /* This gets added */
 };

/* During pool_new, set tag */
new_pool->pool_tag = LOD_POOL_TAG;

Just a referance... common function to be called as below...


+void *comm_pool_find(struct obd_device *obd, char *poolname,
+                    enum comm_pool_type tag)
+{
+       struct lod_pool_desc *lodpd = NULL;
+       struct lov_pool_desc *lovpd = NULL;
+       struct lod_device *lod;
+
+       rcu_read_lock();
+       if (tag == LOV_POOL_TAG) {
+               struct lov_obd *lov = &obd->u.lov;
+
+               lovpd = rhashtable_lookup(&lov->lov_pools_hash_body,
+                                         poolname, lov_pools_hash_params);
+               if (lovpd && !atomic_inc_not_zero(&lovpd->pool_refcount))
+                       lovpd = NULL;
+               rcu_read_unlock();
+               return (void *)lovpd;
+       }
+       lod = lu2lod_dev(obd->obd_lu_dev);
+
+       lodpd = rhashtable_lookup(&lod->lod_pools_hash_body, poolname,
+                                 lod_pools_hash_params);
+       if (lodpd && !atomic_inc_not_zero(&lodpd->pool_refcount))
+               lodpd = NULL;
+       rcu_read_unlock();
+       return (void *)lodpd;
+}
+EXPORT_SYMBOL(comm_pool_find);
